import React from 'react'
import { Container } from './style' 

const Hooks = () => {
    const [count, setCount] = React.useState(1);
  return (
    <Container>
          <h1>Hooks</h1>
          <button onClick={() => setCount(count + 1)}>+</button>
          <div>{count}</div>
          <button onClick={() => setCount(count - 1)}>-</button>
          
    </Container>
  )
}

export default Hooks
